function renderPublic(){destroyCharts();$('publicShell').innerHTML=`<div class="public-screen"><div class="public-card"><div class="brand-panel"><div class="kicker">OS v13.0.5.1 · Private by design</div><h1>Port<span class="brand-accent">OS</span></h1><p>Connect your authorised private data source to load your portfolio dashboard.</p></div><form class="setup-form" id="connectForm"><div class="field"><label>Apps Script Web App URL</label><input name="endpoint" required autocomplete="off" placeholder="Paste your v13 Apps Script deployment URL"></div><div class="field"><label>Secret Token</label><input name="token" required type="password" placeholder="Stored only on this authorised device"></div><div class="field"><label>Create Local PIN (4–6 digits)</label><input name="pin" required type="password" pattern="[0-9]{4,6}" inputmode="numeric"></div><div class="field"><label>Confirm PIN</label><input name="pin2" required type="password" pattern="[0-9]{4,6}" inputmode="numeric"></div><button class="btn btn-primary wide" type="submit">Connect Securely</button><p class="hint">No personal accounts, categories, balances or assumptions are stored in this public application source.</p></form></div></div>`;$('app').classList.add('hidden');q('#connectForm').onsubmit=connectFirstUse}
