function reportCashRows(month){
  const previous=beforeMonth(month),openBalances=balancesForMonth(previous),allTx=S.data?.transactions||[];
  return Object.values(maps().accounts).filter(a=>bool(a.include_in_liquid_cash)).map(a=>{
    const id=key(a.account_id),tx=transactions(month),opening=openBalances[id]?.amount||0;
    const income=tx.filter(t=>key(t.transaction_type)==='income'&&key(t.account_id)===id).reduce((s,t)=>s+n(t.amount),0);
    const expense=tx.filter(t=>['expense','split_bill'].includes(key(t.transaction_type))&&key(t.account_id)===id).reduce((s,t)=>s+n(t.amount),0);
    const investment=tx.filter(t=>key(t.transaction_type)==='investment'&&key(t.account_id)===id).reduce((s,t)=>s+n(t.amount),0);
    const transferIn=tx.filter(t=>key(t.transaction_type)==='transfer'&&key(t.to_account_id)===id).reduce((s,t)=>s+n(t.amount),0);
    const transferOut=tx.filter(t=>key(t.transaction_type)==='transfer'&&key(t.from_account_id)===id).reduce((s,t)=>s+n(t.amount),0);
    const receivableOut=tx.filter(t=>key(t.transaction_type)==='receivable_out'&&key(t.account_id)===id).reduce((s,t)=>s+n(t.amount),0);
    const settlementIn=tx.filter(t=>key(t.transaction_type)==='receivable_settlement'&&key(t.account_id)===id).reduce((s,t)=>s+n(t.amount),0);
    const reimbursementIn=allTx.filter(t=>key(t.transaction_type)==='split_bill'&&String(t.reimbursement_date||'').slice(0,7)===month&&key(t.reimbursement_account_id||t.account_id)===id).reduce((s,t)=>s+n(t.reimbursement_amount),0);
    const calculated=opening+income-expense-investment+transferIn-transferOut-receivableOut+settlementIn+reimbursementIn;
    const confirmed=(S.data?.accountBalances||[]).find(b=>b.reporting_month===month&&key(b.account_id)===id&&String(b.actual_balance??'')!=='');
    const ending=confirmed?n(confirmed.actual_balance):calculated,variance=confirmed?ending-calculated:0;
    const status=confirmed?(Math.abs(variance)<=1?'Reconciled':'Variance Detected'):(monthHasEnded(month)?'Pending Confirmation':'Current Position');
    return{id,label:a.display_name,opening,income,expense,investment,transferIn,transferOut,receivableOut,settlementIn,reimbursementIn,calculated,ending,variance,status};
  });
}
function reportInstrumentForIncomeCategory(categoryId){
  const id=key(categoryId);if(id.includes('deposit'))return 'bni_deposito';if(id.includes('sbn_existing'))return 'bni_sbn';if(id.includes('sr025'))return 'sr025';if(id.includes('rd'))return 'bni_rd';return '';
}
function reportForecastInvestmentReturn(month){
  const planned=planRows(month,'income').filter(p=>bool(maps().categories[key(p.category_id)]?.include_in_investment_earnings));
  const actual=transactions(month).filter(t=>key(t.transaction_type)==='income'&&bool(maps().categories[key(t.category_id)]?.include_in_investment_earnings));
  const ids=[...new Set([...planned.map(p=>key(p.category_id)),...actual.map(t=>key(t.category_id))])];
  let cashIncome=0,valuation=0;
  ids.forEach(id=>{
    const category=maps().categories[id],plannedAmount=planned.filter(p=>key(p.category_id)===id).reduce((s,p)=>s+n(p.planned_amount),0),actualAmount=actual.filter(t=>key(t.category_id)===id).reduce((s,t)=>s+n(t.amount),0),value=actualAmount>0?actualAmount:plannedAmount;
    if(!bool(category?.allow_transaction_entry))valuation+=value; else cashIncome+=value;
  });
  return{cashIncome,valuation,totalReturn:cashIncome+valuation};
}
function reportInvestmentData(month,basis){
  const prev=beforeMonth(month),openingRows=Object.fromEntries(estimateHoldingRows(prev).map(r=>[key(r.instrument_id),n(r.amount)])),endingRows=Object.fromEntries(estimateHoldingRows(month).map(r=>[key(r.instrument_id),n(r.amount)]));
  const cashTx=transactions(month).filter(t=>key(t.transaction_type)==='income'&&bool(maps().categories[key(t.category_id)]?.include_in_investment_earnings));
  const rows=Object.values(maps().instruments).filter(i=>bool(i.active)&&bool(i.include_in_total_portfolio)).map(i=>{
    const id=key(i.instrument_id),opening=openingRows[id]||0,ending=endingRows[id]||opening,contribution=transactions(month).filter(t=>key(t.transaction_type)==='investment'&&key(t.instrument_id)===id).reduce((s,t)=>s+n(t.amount),0);
    const cashIncome=cashTx.filter(t=>key(reportInstrumentForIncomeCategory(t.category_id))===id).reduce((s,t)=>s+n(t.amount),0);
    const method=key(i.valuation_method),valuationBased=['manual_market_value_confirmable','manual_market_value','manual_gold_gross_with_financing'].includes(method);
    const valuation=valuationBased?ending-opening-contribution:0;
    const result=cashIncome+valuation;
    const basisLabel=method==='manual_gold_gross_with_financing'?'Buyback valuation basis':method.includes('market_value')?'Market valuation basis':method==='fixed_principal_with_payout'?'Cash income / principal basis':'Contribution balance basis';
    return{id,label:i.display_name,opening,contribution,cashIncome,valuation,ending,result,basisLabel};
  }).filter(r=>r.opening||r.contribution||r.cashIncome||r.ending||r.valuation);
  const allocated=rows.reduce((s,r)=>s+r.cashIncome,0),cashIncome=cashTx.reduce((s,t)=>s+n(t.amount),0),unallocated=cashIncome-allocated,valuation=rows.reduce((s,r)=>s+r.valuation,0),contribution=rows.reduce((s,r)=>s+r.contribution,0);
  const availableReturn={cashIncome,valuation,totalReturn:cashIncome+valuation};
  const reportReturn=basis.type==='interim'?reportForecastInvestmentReturn(month):availableReturn;
  return{rows,cashIncome,unallocated,valuation,contribution,totalReturn:cashIncome+valuation,availableReturn,reportReturn};
}
function reportReceivableData(month){
  const previous=beforeMonth(month),tx=S.data?.transactions||[],rows=[];
  (S.data?.receivables||[]).forEach(r=>{
    const outs=tx.filter(t=>t.receivable_id===r.receivable_id&&key(t.transaction_type)==='receivable_out'),settle=tx.filter(t=>t.receivable_id===r.receivable_id&&key(t.transaction_type)==='receivable_settlement');
    const principal=n(r.original_amount)||outs.reduce((s,t)=>s+n(t.amount),0),opened=String(r.origination_date||outs[0]?.transaction_date||'').slice(0,7);
    const settledBefore=settle.filter(t=>t.reporting_month<=previous).reduce((s,t)=>s+n(t.amount),0),opening=opened&&opened<=previous?Math.max(0,principal-settledBefore):0;
    const newAmount=outs.filter(t=>t.reporting_month===month).reduce((s,t)=>s+n(t.amount),0)||(opened===month?principal:0);
    const received=settle.filter(t=>t.reporting_month===month).reduce((s,t)=>s+n(t.amount),0),closing=Math.max(0,opening+newAmount-received);
    if(opening||newAmount||received||closing)rows.push({label:r.short_reference||'Receivable',type:'Personal Receivable',opening,newAmount,received,closing,status:closing===0?'Settled':received>0?'Partially Settled':opening>0?'Carried Forward':'Open'});
  });
  tx.filter(t=>key(t.transaction_type)==='split_bill').forEach(t=>{
    const opened=t.reporting_month,receivedMonth=String(t.reimbursement_date||'').slice(0,7),principal=n(t.reimbursable_amount),paidBefore=receivedMonth&&receivedMonth<=previous?n(t.reimbursement_amount):0;
    const opening=opened<month?Math.max(0,principal-paidBefore):0,newAmount=opened===month?principal:0,received=receivedMonth===month?n(t.reimbursement_amount):0,closing=Math.max(0,opening+newAmount-received);
    if(opening||newAmount||received||closing)rows.push({label:String(t.note||'Split Bill Reimbursement').trim()||'Split Bill Reimbursement',type:'Split Bill',opening,newAmount,received,closing,status:closing===0?'Reimbursed':received>0?'Partially Reimbursed':opening>0?'Pending Reimbursement · Carried Forward':'Pending Reimbursement'});
  });
  return{rows,opening:rows.reduce((s,r)=>s+r.opening,0),newAmount:rows.reduce((s,r)=>s+r.newAmount,0),received:rows.reduce((s,r)=>s+r.received,0),closing:rows.reduce((s,r)=>s+r.closing,0),openCount:rows.filter(r=>r.closing>0).length};
}
function monthlyReportData(month){
  const basis=reportBasisFor(month),incomeRows=reportIncomeRows(month),expense=reportExpenseData(month),cash=reportCashRows(month),investment=reportInvestmentData(month,basis),receivables=reportReceivableData(month),forecast=monthlyForecast(month),opening=snapshotTotal(beforeMonth(month)),ending=reportEndingValue(month,basis);
  const actualIncome=incomeRows.reduce((s,r)=>s+r.actual,0),actualInvestment=actualByType(month,'investment'),actualNet=actualIncome-expense.total-actualInvestment,growth=ending-opening,growthPct=opening?growth/opening*100:0;
  const incomeBridge=basis.type==='interim'?forecast.income:actualIncome,expenseBridge=basis.type==='interim'?forecast.expense:expense.total,bridgeReturn=investment.reportReturn;
  const returnAlreadyInsideIncome=basis.type==='interim'?bridgeReturn.totalReturn:bridgeReturn.cashIncome;
  const nonInvestmentIncome=incomeBridge-returnAlreadyInsideIncome,explained=opening+nonInvestmentIncome+bridgeReturn.totalReturn-expenseBridge,variance=ending-explained;
  const reconcileStatus=basis.type==='final'?(Math.abs(variance)<=1?'Reconciled':'Variance Detected'):(Math.abs(variance)<=1?'Pending Confirmation':'Pending Confirmation');
  return{month,basis,incomeRows,expense,cash,investment,receivables,forecast,opening,ending,actualIncome,actualInvestment,actualNet,growth,growthPct,nonInvestmentIncome,expenseBridge,bridgeReturn,explained,variance,reconcileStatus};
}
function reportKpi(label,value,sub,cls=''){return `<div class="report-kpi"><div class="report-kpi-label">${esc(label)}</div><div class="report-kpi-value ${cls}">${value}</div><div class="report-kpi-sub">${sub||''}</div></div>`}
function reportTable(headers,rows,classes=''){return `<div class="report-table-wrap"><table class="report-table ${classes}"><thead><tr>${headers.map(h=>`<th>${esc(h)}</th>`).join('')}</tr></thead><tbody>${rows.join('')}</tbody></table></div>`}
function reportSummaryHtml(d){
  return `<section class="report-section"><h2>Executive Summary</h2><div class="report-kpi-grid">${reportKpi(d.basis.portfolioLabel,reportMoney(d.ending),d.basis.type==='interim'?'Updated Forecast basis':d.basis.type==='final'?'Confirmed closing snapshot':'Available month-end basis')}${reportKpi(d.basis.growthLabel,reportMoney(d.growth),reportPct(d.growthPct),d.growth>=0?'pos':'neg')}${reportKpi('Total Income',reportMoney(d.actualIncome),d.basis.type==='interim'?'Actual recorded to date':'Actual recorded')}${reportKpi('Total Expenses',reportMoney(d.expense.total),d.basis.type==='interim'?'Actual recorded to date':'Actual recorded','neg')}${reportKpi('Net Cash Flow',reportMoney(d.actualNet),'Income − expenses − contribution',d.actualNet>=0?'pos':'neg')}${reportKpi('Investment Contribution',reportMoney(d.actualInvestment),'New money invested','blue')}${reportKpi(d.basis.returnLabel,reportMoney(d.bridgeReturn.totalReturn),d.basis.type==='interim'?'Updated Forecast cash income + valuation change':'Cash income + valuation change',d.bridgeReturn.totalReturn>=0?'pos':'neg')}${reportKpi('Outstanding Receivables',reportMoney(d.receivables.closing),`${d.receivables.openCount} open item(s)`)}</div></section>`;
}
function reportOtherIncomeDrilldown(d){
  const otherRows=d.incomeRows.filter(r=>r.actual>0&&(key(r.id).includes('other')||key(r.label).includes('other income')));
  if(!otherRows.length)return'';
  const otherIds=new Set(otherRows.map(r=>key(r.id))),items={};
  transactions(d.month).filter(t=>key(t.transaction_type)==='income'&&otherIds.has(key(t.category_id))).forEach(t=>{
    const note=String(t.note||'Unspecified other income').trim()||'Unspecified other income',k=key(note);
    items[k]=items[k]||{label:note,amount:0,count:0};items[k].amount+=n(t.amount);items[k].count++;
  });
  const grouped=Object.values(items).sort((a,b)=>b.amount-a.amount),total=grouped.reduce((s,x)=>s+x.amount,0);
  if(!total)return'';
  const rows=grouped.map(x=>`<tr><td>${esc(x.label)}${x.count>1?`<small>${x.count} recorded entries</small>`:''}</td><td class="num">${reportMoney(x.amount)}</td><td class="num">${(x.amount/total*100).toFixed(1)}%</td></tr>`);
  rows.push(`<tr class="total"><td>Total Other Income</td><td class="num">${reportMoney(total)}</td><td class="num">100.0%</td></tr>`);
  const top=grouped.slice(0,2).map(x=>`${x.label} (${reportMoney(x.amount)})`).join(' and ');
  const planned=otherRows.reduce((s,r)=>s+r.planned,0),variance=total-planned;
  const narrative=`Other Income contributed ${reportMoney(total)} during the reporting period${variance!==0?`, creating ${variance>=0?'a positive':'a negative'} variance of ${reportMoney(Math.abs(variance))} versus plan`:''}${top?`. The main driver${grouped.length>1?'s were':' was'} ${top}`:''}. Treat these items as note-based explanations of income variance, not recurring income unless they are expected to repeat.`;
  return `<h3>Other Income Breakdown</h3>${reportTable(['Other Income Detail / Note','Amount','Share'],rows)}<div class="report-insight"><strong>Income Driver Insight</strong><p>${esc(narrative)}</p></div>`;
}
function reportIncomeHtml(d){
  const rows=d.incomeRows.map(r=>`<tr><td>${esc(r.label)}</td><td class="num">${reportMoney(r.planned)}</td><td class="num">${reportMoney(r.actual)}</td><td class="num ${r.variance>=0?'pos':'neg'}">${reportSigned(r.variance)}</td></tr>`);
  rows.push(`<tr class="total"><td>Total Income</td><td class="num">${reportMoney(d.incomeRows.reduce((s,r)=>s+r.planned,0))}</td><td class="num">${reportMoney(d.actualIncome)}</td><td class="num">${reportSigned(d.actualIncome-d.incomeRows.reduce((s,r)=>s+r.planned,0))}</td></tr>`);
  return `<section class="report-section"><h2>Income Analysis</h2><p class="report-caption">Planned versus actual genuine income. Internal transfers and investment valuation changes are not classified as income.</p>${reportTable(['Income Category','Planned','Actual','Variance'],rows)}${reportOtherIncomeDrilldown(d)}</section>`;
}
function reportExpenseNarrative(e){
  const dominant=e.incidentalItems[0],variance=e.regularBudget-e.regularActual,repeat=e.repeats[0];
  let text=`Total personal expenses are ${reportMoney(e.total)}. Regular budget performance is ${variance>=0?`${reportMoney(variance)} below budget`:`${reportMoney(Math.abs(variance))} above budget`}.`;
  if(e.incidental>0)text+=` Incidental spending of ${reportMoney(e.incidental)} is shown separately${dominant?`, led by ${dominant.label} (${reportMoney(dominant.amount)})`:''}.`;
  if(repeat)text+=` Repeated note pattern: ${repeat.label} appears ${repeat.count} times, totalling ${reportMoney(repeat.amount)}.`;
  if(e.unclear.length)text+=` ${e.unclear.length} item(s) have blank or unclear descriptions and may reduce analysis quality.`;
  return text;
}
function reportExpenseDrilldownHtml(item){
  const itemRows=item.items.map(x=>`<tr><td>${esc(x.label)}${x.count>1?`<small>${x.count} recorded entries</small>`:''}</td><td class="num">${reportMoney(x.amount)}</td><td class="num">${item.actual?`${(x.amount/item.actual*100).toFixed(1)}%`:'—'}</td></tr>`);
  itemRows.push(`<tr class="total"><td>Total ${esc(item.label)}</td><td class="num">${reportMoney(item.actual)}</td><td class="num">100.0%</td></tr>`);
  const status=item.actual>item.budget?`Over budget by ${reportMoney(item.actual-item.budget)}`:`Below budget by ${reportMoney(item.budget-item.actual)}`;
  const title=item.mode==='installment'?'Installment Analysis':item.mode==='rizka'?'Rizka Analysis':`${item.label} — Over-Budget Analysis`;
  let extra='';
  if(item.mode==='installment')extra=`<div class="report-highlight-card"><strong>Credit Card Expense Subtotal</strong><span>${reportMoney(item.ccTotal)}</span><small>${item.ccItems.length?item.ccItems.map(x=>esc(x.label)).join(' + '):'No credit-card note identified for this month.'}</small></div>`;
  if(item.mode==='rizka'&&item.relatedIncidentalTotal>0)extra=`<div class="report-note">Additional Rizka-related incidental spending recorded separately: <strong>${reportMoney(item.relatedIncidentalTotal)}</strong> (${item.relatedIncidental.map(x=>esc(x.label)).join(', ')}). This amount remains excluded from regular Rizka budget performance.</div>`;
  return `<div class="report-drilldown"><div class="report-drilldown-head"><h4>${esc(title)}</h4><span class="${item.actual>item.budget?'neg':'pos'}">${esc(status)}</span></div>${reportTable(['Detail / Note','Amount','Share'],itemRows)}${extra}</div>`;
}
function reportExpenseHtml(d){
  const e=d.expense,regular=e.regular.map(r=>`<tr><td>${esc(r.label)}</td><td class="num">${reportMoney(r.budget)}</td><td class="num">${reportMoney(r.actual)}</td><td class="num ${r.variance>=0?'pos':'neg'}">${r.variance>=0?`${reportMoney(r.variance)} under`:`${reportMoney(Math.abs(r.variance))} over`}</td></tr>`);
  regular.push(`<tr class="total"><td>Regular Total</td><td class="num">${reportMoney(e.regularBudget)}</td><td class="num">${reportMoney(e.regularActual)}</td><td class="num">${reportSigned(e.regularBudget-e.regularActual)}</td></tr>`);
  const incidental=e.incidentalItems.map(x=>`<tr><td>${esc(x.label)}</td><td class="num">${reportMoney(x.amount)}</td><td class="num">${e.incidental?`${(x.amount/e.incidental*100).toFixed(1)}%`:'—'}</td></tr>`);
  if(incidental.length)incidental.push(`<tr class="total"><td>Total Incidental</td><td class="num">${reportMoney(e.incidental)}</td><td class="num">100.0%</td></tr>`);
  const major=e.major.map(x=>`<li><strong>${esc(x.category)}</strong> — ${esc(x.note)}: ${reportMoney(x.amount)}</li>`).join('');
  const overBudget=e.overBudget.map(r=>`<tr><td>${esc(r.label)}</td><td class="num">${reportMoney(r.budget)}</td><td class="num">${reportMoney(r.actual)}</td><td class="num neg">${reportMoney(r.actual-r.budget)}</td></tr>`);
  const drilldowns=e.drilldowns.map(reportExpenseDrilldownHtml).join('');
  return `<section class="report-section"><h2>Expense Analysis</h2><div class="report-mini-grid">${reportKpi('Total Expenses',reportMoney(e.total),'Regular + incidental','neg')}${reportKpi('Regular Expenses',reportMoney(e.regularActual),`Budget: ${reportMoney(e.regularBudget)}`)}${reportKpi('Incidental Expenses',reportMoney(e.incidental),'Actual-only exceptional spending','blue')}${reportKpi('Regular Budget Variance',reportMoney(Math.abs(e.regularBudget-e.regularActual)),e.regularBudget>=e.regularActual?'Below budget':'Above budget',e.regularBudget>=e.regularActual?'pos':'neg')}</div><h3>Regular Budget Performance</h3>${reportTable(['Expense Category','Budget','Actual','Variance'],regular)}${overBudget.length?`<h3>Over-Budget Categories</h3>${reportTable(['Category','Budget','Actual','Over Budget'],overBudget)}`:''}<h3>Selected Category Deep Dives</h3>${drilldowns||'<p class="report-caption">No targeted or over-budget regular expense categories recorded for this month.</p>'}<h3>Incidental Expenses</h3>${incidental.length?reportTable(['Incidental Item / Note','Amount','Share'],incidental):'<p class="report-caption">No incidental expenses recorded.</p>'}<div class="report-insight"><strong>Note-Based Spending Insight</strong><p>${esc(reportExpenseNarrative(e))}</p>${major?`<ul>${major}</ul>`:''}</div></section>`;
}
